mapper.select:
SELECT es.id, es.plant_id, p.name AS plant_name, es.target_month, es.electricity_score, es.gas_score, es.water_score, es.solar_score, es.peak_score, es.carbon_score, es.total_score, es.grade FROM esg_scores es JOIN plants p ON p.id = es.plant_id
AND es.target_month = #{targetMonth}
ORDER BY es.target_month DESC, es.total_score DESC, es.id DESC

WITH usage_by_plant AS ( SELECT es.plant_id, COUNT(*) AS measurement_count, MAX(es.summary_at) AS latest_measured_at, ROUND(COALESCE(SUM(electricity_kwh), 0), 2) AS electricity_kwh, ROUND(COALESCE(SUM(gas_m3), 0), 2) AS gas_m3, ROUND(COALESCE(SUM(water_ton), 0), 2) AS water_ton, ROUND(COALESCE(SUM(solar_kwh), 0), 2) AS solar_kwh, ROUND(COALESCE(MAX(peak_kw), 0), 2) AS max_peak_kw, ROUND(COALESCE(MAX(peak_kw), 0), 2) AS interval_max_peak_kw FROM energy_summaries es WHERE es.summary_type = 'DAILY' AND es.facility_id IS NULL AND es.summary_at >= #{from} AND es.summary_at < #{to} AND es.plant_id = #{plantId} GROUP BY es.plant_id ), latest_summary AS ( SELECT es.plant_id, es.peak_kw AS current_peak_kw FROM energy_summaries es JOIN ( SELECT plant_id, MAX(summary_at) AS summary_at FROM energy_summaries WHERE summary_type = 'DAILY' AND facility_id IS NULL AND summary_at >= #{from} AND summary_at < #{to} AND plant_id = #{plantId} GROUP BY plant_id ) latest ON latest.plant_id = es.plant_id AND latest.summary_at = es.summary_at WHERE es.summary_type = 'DAILY' AND es.facility_id IS NULL ), facility_counts AS ( SELECT plant_id, COUNT(*) AS facility_count FROM facilities GROUP BY plant_id ) SELECT p.id AS plant_id, p.name AS plant_name, p.latitude, p.longitude, COALESCE(fc.facility_count, 0) AS facility_count, COALESCE(ubp.measurement_count, 0) AS measurement_count, ubp.latest_measured_at, COALESCE(ubp.electricity_kwh, 0) AS electricity_kwh, COALESCE(ubp.gas_m3, 0) AS gas_m3, COALESCE(ubp.water_ton, 0) AS water_ton, COALESCE(ubp.solar_kwh, 0) AS solar_kwh, COALESCE(ls.current_peak_kw, 0) AS current_peak_kw, COALESCE(ubp.max_peak_kw, 0) AS max_peak_kw, COALESCE(ubp.interval_max_peak_kw, 0) AS interval_max_peak_kw FROM plants p LEFT JOIN facility_counts fc ON fc.plant_id = p.id LEFT JOIN usage_by_plant ubp ON ubp.plant_id = p.id LEFT JOIN latest_summary ls ON ls.plant_id = p.id
AND p.id = #{plantId}
ORDER BY p.name ASC
